namespace BgCommon.Script.Runtime.DotNet;/// <summary>/// 提供有关 .NET 运行环境的信息和操作./// </summary>public class DotNetEnvironment{    /// <summary>    /// 存储当前 .NET 环境的语义化版本.    /// </summary>    private static readonly SemanticVersion EnvironmentVersion = new(Environment.Version);    /// <summary>    /// Initializes a new instance of the <see cref="DotNetEnvironment"/> class.    /// </summary>    public DotNetEnvironment()    {    }    /// <summary>    /// 获取当前 .NET 运行时版本.    /// </summary>    /// <returns>返回 <see cref="SemanticVersion"/> 类型的版本信息.</returns>    public SemanticVersion GetCurrentDotNetRuntimeVersion() => EnvironmentVersion;    /// <summary>    /// 获取指定名称的环境变量值.    /// </summary>    /// <param name="name">环境变量的名称.</param>    /// <returns>环境变量的值; 如果未找到, 则返回 null.</returns>    public string? GetEnvironmentVariable(string name)    {        return Environment.GetEnvironmentVariable(name);    }}